  "description": "An advanced AI-driven suite for inventors and legal teams to analyze concepts, perform prior art searches, draft patent claims, and monitor intellectual property portfolios with professional-grade precision."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
