export enum View {
  DASHBOARD = 'DASHBOARD',
  ANALYSIS = 'ANALYSIS',
  DRAFTING = 'DRAFTING',
  MONITORING = 'MONITORING',
  COLLABORATION = 'COLLABORATION'
}

export interface InventionProfile {
  title: string;
  description: string;
  summary?: string;
  keywords?: string[];
  classification?: string;
  noveltyScore?: number;
  missingDetails?: string[];
}

export interface PriorArtItem {
  title: string;
  uri: string;
  snippet: string;
  relevance: 'High' | 'Medium' | 'Low';
}

export interface PatentDraft {
  abstract: string;
  claims: string[];
  description: string;
  legalFlags: string[];
}

export interface Task {
  id: string;
  title: string;
  status: 'Pending' | 'In Progress' | 'Completed';
  assignee: string;
}

export interface Project {
  id: string;
  invention: InventionProfile;
  priorArt: PriorArtItem[];
  draft?: PatentDraft;
  tasks: Task[];
  status: 'Draft' | 'Review' | 'Filed';
  lastUpdated: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { InventionProfile, PatentDraft, PriorArtItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeInvention = async (description: string): Promise<InventionProfile> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this invention description: "${description}". 
    Provide a structured technical summary, keywords, suggested IP classification (IPC/CPC), 
    and identify missing details to strengthen disclosure. 
    Also estimate a novelty score (0-100) based on typical industry knowledge.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          summary: { type: Type.STRING },
          keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
          classification: { type: Type.STRING },
          noveltyScore: { type: Type.NUMBER },
          missingDetails: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["title", "summary", "keywords", "classification", "noveltyScore", "missingDetails"]
      },
    },
  });

  return JSON.parse(response.text || '{}');
};

export const searchPriorArt = async (invention: InventionProfile): Promise<PriorArtItem[]> => {
  const query = `Patents and prior art related to ${invention.title}: ${invention.keywords?.join(', ')}`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: query,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return chunks.map((chunk: any) => ({
    title: chunk.web?.title || 'Related Patent/Document',
    uri: chunk.web?.uri || '#',
    snippet: chunk.web?.title || 'Snippet unavailable',
    relevance: 'Medium'
  }));
};

export const draftPatent = async (invention: InventionProfile): Promise<PatentDraft> => {
  const prompt = `Draft a formal patent for the following invention:
  Title: ${invention.title}
  Summary: ${invention.summary}
  Keywords: ${invention.keywords?.join(', ')}

  Provide an Abstract, a set of 3-5 main Claims (one independent, others dependent), 
  a brief Detailed Description, and a list of Legal Flags (potential issues for USPTO/EPO).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          abstract: { type: Type.STRING },
          claims: { type: Type.ARRAY, items: { type: Type.STRING } },
          description: { type: Type.STRING },
          legalFlags: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["abstract", "claims", "description", "legalFlags"]
      },
    },
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithAdvisor = async (history: { role: string, message: string }[], userQuery: string) => {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: 'You are an expert Patent Attorney and IP Advisor. Provide precise, legally aware guidance. If uncertain about high-risk legal matters, recommend human legal review.',
    }
  });

  // Re-build history
  for (const turn of history.slice(0, -1)) {
    // Note: Simple simplified version as Chat API expects turns
  }

  const result = await chat.sendMessage({ message: userQuery });
  return result.text;
};

import React, { useState, useEffect } from 'react';
import { View, Project, InventionProfile, PatentDraft, PriorArtItem } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import InventionForm from './components/InventionForm';
import AnalysisReport from './components/AnalysisReport';
import DraftingTool from './components/DraftingTool';
import ChatBot from './components/ChatBot';
import { analyzeInvention, searchPriorArt, draftPatent } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Initialize with some mock data if empty
  useEffect(() => {
    const savedProjects = localStorage.getItem('patentiai_projects');
    if (savedProjects) {
      setProjects(JSON.parse(savedProjects));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('patentiai_projects', JSON.stringify(projects));
  }, [projects]);

  const handleStartAnalysis = async (description: string) => {
    setIsProcessing(true);
    try {
      const analysis = await analyzeInvention(description);
      const priorArt = await searchPriorArt(analysis);

      const newProject: Project = {
        id: Date.now().toString(),
        invention: { ...analysis, description },
        priorArt,
        tasks: [
          { id: '1', title: 'Review AI Analysis', status: 'Pending', assignee: 'Lead Attorney' },
          { id: '2', title: 'Verify Prior Art', status: 'Pending', assignee: 'Researcher' }
        ],
        status: 'Draft',
        lastUpdated: new Date().toISOString()
      };

      setProjects([newProject, ...projects]);
      setCurrentProject(newProject);
      setCurrentView(View.ANALYSIS);
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Failed to analyze invention. Please check your API key and input.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenerateDraft = async () => {
    if (!currentProject) return;
    setIsProcessing(true);
    try {
      const draft = await draftPatent(currentProject.invention);
      const updatedProject = { ...currentProject, draft, lastUpdated: new Date().toISOString() };
      setCurrentProject(updatedProject);
      setProjects(projects.map(p => p.id === updatedProject.id ? updatedProject : p));
      setCurrentView(View.DRAFTING);
    } catch (error) {
      console.error("Drafting failed", error);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />

      <main className="flex-1 overflow-y-auto relative p-4 md:p-8">
        <header className="mb-8 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">
              {currentView === View.DASHBOARD && "IP Portfolio Dashboard"}
              {currentView === View.ANALYSIS && "Invention Analysis"}
              {currentView === View.DRAFTING && "Patent Drafting Suite"}
              {currentView === View.MONITORING && "IP Monitoring & Alerts"}
            </h1>
            <p className="text-slate-500">
              {currentProject ? `Project: ${currentProject.invention.title}` : "Manage your intellectual property assets."}
            </p>
          </div>
          {currentProject && currentView !== View.DASHBOARD && (
            <button 
              onClick={() => setCurrentView(View.DASHBOARD)}
              className="bg-white border border-slate-200 px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-50 transition shadow-sm"
            >
              Back to Dashboard
            </button>
          )}
        </header>

        <div className="max-w-6xl mx-auto">
          {currentView === View.DASHBOARD && (
            <Dashboard 
              projects={projects} 
              onSelectProject={(p) => { setCurrentProject(p); setCurrentView(View.ANALYSIS); }} 
              onNewProject={() => { setCurrentProject(null); }}
            />
          )}

          {(!currentProject && currentView !== View.DASHBOARD) && (
            <InventionForm onSubmit={handleStartAnalysis} isLoading={isProcessing} />
          )}

          {currentProject && currentView === View.ANALYSIS && (
            <AnalysisReport 
              project={currentProject} 
              onGenerateDraft={handleGenerateDraft} 
              isLoadingDraft={isProcessing}
            />
          )}

          {currentProject && currentView === View.DRAFTING && (
            <DraftingTool project={currentProject} />
          )}
        </div>

        {isProcessing && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-sm z-50 flex items-center justify-center">
            <div className="bg-white p-8 rounded-2xl shadow-2xl flex flex-col items-center max-w-sm text-center">
              <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
              <h3 className="text-xl font-semibold mb-2">Analyzing your Concept</h3>
              <p className="text-slate-600">Our AI is scanning global patent databases and legal frameworks. This may take a minute...</p>
            </div>
          </div>
        )}

        <ChatBot currentProject={currentProject} />
      </main>
    </div>
  );
};

export default App;

