interface AuthProps {
  onLogin: (user: User) => void;
  onBack?: () => void;
}

declare global {
  interface Window {
    google: any;
  }
}

const Auth: React.FC<AuthProps> = ({ onLogin, onBack }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>('Inventor');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const googleButtonRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize Google Sign-In
    if (window.google && window.google.accounts && window.google.accounts.id) {
      const clientId = process.env.GOOGLE_CLIENT_ID; // Ensure this is set in your environment

      if (clientId) {
        window.google.accounts.id.initialize({
          client_id: clientId,
          callback: handleGoogleCredentialResponse,
          auto_select: false,
          cancel_on_tap_outside: true
        });

        window.google.accounts.id.renderButton(
          googleButtonRef.current,
          { theme: 'outline', size: 'large', width: '100%' }
        );
      } else {
        console.warn("Google Client ID not found. OAuth button will not render.");
      }
    }
  }, [isLogin]); // Re-render button when mode changes just in case

  const handleGoogleCredentialResponse = async (response: any) => {
    setIsLoading(true);
    setError(null);
    try {
      const user = await authService.loginWithGoogle(response.credential);
      onLogin(user);
    } catch (err: any) {
      setError(err.message || "Google Login failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      let user: User;
      if (isLogin) {
        user = await authService.login(email, password);
      } else {
        // Use provided name or derive from email if empty (fallback)
        const displayName = name.trim() || email.split('@')[0];
        user = await authService.register(displayName, email, password, role);
      }
      onLogin(user);
    } catch (err: any) {
      setError(err.message || "Authentication failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const toggleMode = () => {
    setIsLogin(!isLogin);
    setError(null);
    setName('');
    setPassword('');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 px-4 relative">
      {onBack && (
        <button 
          onClick={onBack}
          className="absolute top-8 left-8 text-slate-400 hover:text-white flex items-center gap-2 transition"
        >
          <i className="fa-solid fa-arrow-left"></i> Back to Search
        </button>
      )}

      <div className="max-w-md w-full">
        <div className="text-center mb-10">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-blue-500/20">
            <i className="fa-solid fa-gavel text-white text-2xl"></i>
          </div>
          <h1 className="text-3xl font-bold text-white tracking-tight">PatentiAI</h1>
          <p className="text-slate-400 mt-2">Intellectual Property Management Suite</p>
        </div>

        <div className="bg-white rounded-3xl shadow-2xl p-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-6">{isLogin ? 'Welcome Back' : 'Create Account'}</h2>

          {error && (
            <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-600 text-sm font-medium">
              <i className="fa-solid fa-circle-exclamation"></i>
              {error}
            </div>
          )}

          {/* Google Login Section */}
          <div className="mb-6">
            <div ref={googleButtonRef} className="w-full flex justify-center h-[44px]"></div>
            {!process.env.GOOGLE_CLIENT_ID && (
               <div className="text-center text-[10px] text-slate-400 mt-2 italic">
                 Configure GOOGLE_CLIENT_ID to enable OAuth
               </div>
            )}
            <div className="relative mt-6">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-slate-200"></div>
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="bg-white px-2 text-slate-400 font-medium">Or continue with email</span>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {!isLogin && (
              <>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Access Role</label>
                  <select 
                    className="w-full px-4 py-3 rounded-xl border border-slate-100 bg-slate-50 text-slate-900 focus:ring-2 focus:ring-blue-500 transition"
                    value={role}
                    onChange={(e) => setRole(e.target.value as UserRole)}
                  >
                    <option value="Inventor">Inventor</option>
                    <option value="Attorney">Patent Attorney</option>
                    <option value="Admin">Legal Firm Admin</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Full Name</label>
                  <input 
                    type="text" required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full px-4 py-3 rounded-xl border border-slate-100 bg-slate-50 text-slate-900 focus:ring-2 focus:ring-blue-500 transition"
                    placeholder="John Doe"
                  />
                </div>
              </>
            )}

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Email Address</label>
              <input 
                type="email" required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-slate-100 bg-slate-50 text-slate-900 focus:ring-2 focus:ring-blue-500 transition"
                placeholder="name@company.com"
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Password</label>
              <input 
                type="password" required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-slate-100 bg-slate-50 text-slate-900 focus:ring-2 focus:ring-blue-500 transition"
                placeholder="••••••••"
                minLength={6}
              />
            </div>

            {isLogin && (
              <div className="flex justify-end">
                <button type="button" className="text-xs font-semibold text-blue-600 hover:underline">Forgot password?</button>
              </div>
            )}

            <button 
              type="submit" 
              disabled={isLoading}
              className={`w-full py-4 rounded-xl font-bold shadow-lg shadow-blue-500/20 transition mt-4 flex items-center justify-center gap-2 ${
                isLoading ? 'bg-blue-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 active:scale-[0.98]'
              } text-white`}
            >
              {isLoading ? <i className="fa-solid fa-spinner animate-spin"></i> : (isLogin ? 'Sign In' : 'Get Started')}
            </button>
          </form>

          <div className="mt-8 text-center">
            <button onClick={toggleMode} className="text-sm text-slate-500">
              {isLogin ? "Don't have an account? " : "Already have an account? "}
              <span className="text-blue-600 font-bold hover:underline">{isLogin ? 'Sign Up' : 'Log In'}</span>
            </button>
          </div>
        </div>

        <div className="mt-10 text-center flex justify-center gap-6 text-slate-500 text-xs">
          <span>GDPR Compliant</span>
          <span>AES-256 Encrypted</span>
          <span>Terms of Service</span>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { View, Project, User } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import InventionForm from './components/InventionForm';
import AnalysisReport from './components/AnalysisReport';
import PatentEditor from './components/editor/PatentEditor';
import ChatBot from './components/ChatBot';
import Auth from './components/Auth';
import LandingPage from './components/LandingPage';
import { analyzeInvention, searchPriorArt } from './services/geminiService';
import { authService } from './services/authService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProject, setCurrentProject] = useState<Project | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [authInitialized, setAuthInitialized] = useState(false);
  const [showAuth, setShowAuth] = useState(false);

  // Initialize Auth Session
  useEffect(() => {
    const currentUser = authService.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
    setAuthInitialized(true);
  }, []);

  // Load Projects from persistence (Mock DB)
  useEffect(() => {
    const savedProjects = localStorage.getItem('patentiai_projects');
    if (savedProjects) {
      try {
        setProjects(JSON.parse(savedProjects));
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  // Save Projects to persistence
  useEffect(() => {
    if (projects.length > 0) {
      localStorage.setItem('patentiai_projects', JSON.stringify(projects));
    }
  }, [projects]);

  const handleLogin = (u: User) => {
    setUser(u);
    setShowAuth(false);
  };

  const handleLogout = () => { 
    authService.logout();
    setUser(null); 
    setCurrentView(View.DASHBOARD);
  };

  const handleNewProjectSubmit = async (desc: string) => {
    setIsProcessing(true);
    try {
      const analysis = await analyzeInvention(desc);
      const priorArt = await searchPriorArt(analysis);

      const newPrj: Project = {
        id: `PRJ-${Date.now()}`,
        organizationId: user?.organizationId || 'ORG-1',
        invention: { 
          ...analysis, 
          id: `INV-${Date.now()}`, 
          description: desc,
          riskFlags: [] 
        },
        draft: {
          id: `DFT-${Date.now()}`,
          abstract: '',
          claims: [],
          description: '',
          figures: [],
          status: 'Draft',
          version: 1,
          legalFlags: []
        },
        priorArt,
        tasks: [],
        auditLogs: [{ id: 'L1', timestamp: new Date().toISOString(), userId: user?.id || 'U1', action: 'Project Created', resourceId: 'PRJ', ipAddress: '127.0.0.1' }],
        status: 'Draft'
      };

      setProjects(prev => [newPrj, ...prev]);
      setCurrentProject(newPrj);
      setCurrentView(View.ANALYSIS);
    } finally {
      setIsProcessing(false);
    }
  };

  if (!authInitialized) {
    return <div className="min-h-screen bg-slate-900"></div>; // Loading state
  }

  // State 1: User is logged in -> Show Dashboard
  if (user) {
    return (
      <div className="flex h-screen overflow-hidden bg-[#F1F3F6]">
        <Sidebar 
          currentView={currentView} 
          onViewChange={setCurrentView} 
          onLogout={handleLogout} 
          user={user} 
        />

        <main className="flex-1 overflow-y-auto p-8 relative">
          <header className="flex justify-between items-center mb-10">
            <div>
              <h1 className="text-3xl font-black text-slate-950 tracking-tighter">
                {currentView.replace('_', ' ')}
              </h1>
              <p className="text-slate-500 font-medium">{currentProject?.invention.title || 'Enterprise Management'}</p>
            </div>
            <div className="flex gap-4">
               <div className="flex items-center gap-2 bg-emerald-100 text-emerald-700 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase">
                 <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                 Secure Node Active
               </div>
               {currentProject && (
                 <button onClick={() => setCurrentProject(null)} className="text-slate-400 hover:text-slate-600 transition">
                   <i className="fa-solid fa-circle-xmark text-2xl"></i>
                 </button>
               )}
            </div>
          </header>

          <div className="max-w-7xl mx-auto">
            {currentView === View.DASHBOARD && (
              <Dashboard 
                projects={projects} 
                onSelectProject={(p) => { setCurrentProject(p); setCurrentView(View.ANALYSIS); }} 
                onNewProject={() => { setCurrentProject(null); setCurrentView(View.ANALYSIS); }}
              />
            )}

            {currentView === View.ANALYSIS && !currentProject && (
              <InventionForm onSubmit={handleNewProjectSubmit} isLoading={isProcessing} />
            )}

            {currentView === View.ANALYSIS && currentProject && (
              <AnalysisReport 
                project={currentProject} 
                onGenerateDraft={() => setCurrentView(View.DRAFTING)} 
                isLoadingDraft={isProcessing} 
              />
            )}

            {currentView === View.DRAFTING && currentProject && (
              <PatentEditor project={currentProject} onUpdate={(p) => setProjects(projects.map(prj => prj.id === p.id ? p : prj))} />
            )}

            {currentView === View.AUDIT_LOGS && (
               <div className="bg-white rounded-3xl p-8 border border-slate-200">
                 <h2 className="text-xl font-black mb-6">Access Audit Trails</h2>
                 <div className="space-y-2">
                   {projects.flatMap(p => p.auditLogs).map(log => (
                     <div key={log.id} className="flex gap-4 items-center p-4 bg-slate-50 rounded-xl border border-slate-100 font-mono text-[10px]">
                       <span className="text-slate-400">{log.timestamp}</span>
                       <span className="bg-blue-100 text-blue-600 px-2 py-0.5 rounded font-bold uppercase">ACTION: {log.action}</span>
                       <span className="text-slate-900 font-bold">USER_ID: {log.userId}</span>
                       <span className="ml-auto text-slate-300">IP: {log.ipAddress}</span>
                     </div>
                   ))}
                 </div>
               </div>
            )}
          </div>

          {isProcessing && (
             <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-xl z-[100] flex items-center justify-center">
               <div className="text-center">
                  <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-6 shadow-2xl shadow-blue-500/20"></div>
                  <h3 className="text-3xl font-black text-white tracking-tighter">Neural Engine Processing</h3>
                  <p className="text-blue-200 mt-2 font-medium">Encrypting transmission and scanning global data vectors...</p>
               </div>
             </div>
          )}

          <ChatBot currentProject={currentProject} />
        </main>
      </div>
    );
  }

  // State 2: User requests Auth from Landing
  if (showAuth) {
    return <Auth onLogin={handleLogin} onBack={() => setShowAuth(false)} />;
  }

  // State 3: Default Landing Page (Public)
  return <LandingPage onAuthRequest={() => setShowAuth(true)} />;
};

export default App;

import React, { useState } from 'react';
import { performPublicSearch } from '../services/geminiService';
import { PublicSearchResult } from '../types';

interface LandingPageProps {
  onAuthRequest: () => void;
}

const LandingPage: React.FC<LandingPageProps> = ({ onAuthRequest }) => {
  const [query, setQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [result, setResult] = useState<PublicSearchResult | null>(null);

  const suggestions = [
    "A biodegradable coffee cup that seeds plants",
    "AI-powered drone for automated window cleaning",
    "Smart contact lenses for glucose monitoring",
    "Blockchain-based voting system for HOAs"
  ];

  const handleSearch = async (e: React.FormEvent | string) => {
    if (typeof e !== 'string') e.preventDefault();
    const searchQuery = typeof e === 'string' ? e : query;

    if (!searchQuery.trim()) return;
    if (typeof e === 'string') setQuery(e);

    setIsSearching(true);
    setResult(null); // Reset previous results
    try {
      const data = await performPublicSearch(searchQuery);
      setResult(data);
    } catch (error) {
      console.error("Search failed", error);
    } finally {
      setIsSearching(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col text-slate-900 font-sans selection:bg-blue-100">
      {/* Header */}
      <header className="flex justify-between items-center p-6 lg:px-12 sticky top-0 z-50 bg-slate-50/80 backdrop-blur-md">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => setResult(null)}>
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-600/20">
            <i className="fa-solid fa-gavel text-white text-lg"></i>
          </div>
          <span className="text-xl font-black tracking-tight text-slate-900">PatentiAI</span>
        </div>
        <button 
          onClick={onAuthRequest}
          className="px-6 py-2.5 bg-slate-900 text-white rounded-full text-sm font-bold hover:bg-slate-800 transition shadow-lg shadow-slate-200 active:scale-95"
        >
          Sign In
        </button>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center p-6 lg:p-12 max-w-5xl mx-auto w-full">

        {/* Hero Section */}
        <div className={`text-center transition-all duration-700 ease-out ${result || isSearching ? 'mt-0 mb-8 opacity-100 scale-100' : 'mt-20 mb-10'}`}>
          <h1 className="text-4xl md:text-7xl font-black text-slate-900 tracking-tighter mb-6">
            Is your idea <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">patentable?</span>
          </h1>
          <p className={`text-slate-500 text-lg md:text-xl font-medium max-w-2xl mx-auto transition-opacity duration-500 ${result ? 'opacity-0 h-0 overflow-hidden' : 'opacity-100'}`}>
            Instant prior art search and novelty assessment powered by Gemini 2.0 Flash.
          </p>
        </div>

        {/* Search Input */}
        <div className="w-full max-w-3xl relative z-20">
          <form onSubmit={handleSearch} className="relative">
            <div className="relative group">
              <div className={`absolute inset-0 bg-gradient-to-r from-blue-500 to-indigo-500 rounded-3xl blur opacity-20 group-hover:opacity-30 transition duration-500 ${isSearching ? 'animate-pulse' : ''}`}></div>
              <div className="relative bg-white rounded-3xl shadow-xl shadow-blue-900/5 border border-slate-200 flex items-center overflow-hidden transition-shadow focus-within:shadow-2xl focus-within:shadow-blue-900/10">
                <textarea
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={(e) => {
                    if(e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSearch(e);
                    }
                  }}
                  placeholder="Describe your invention here..."
                  className="w-full p-6 text-lg text-slate-800 placeholder:text-slate-400 focus:outline-none resize-none bg-transparent min-h-[80px]"
                  rows={result ? 1 : 2}
                  disabled={isSearching}
                />
                <button 
                  type="submit" 
                  disabled={isSearching || !query.trim()}
                  className={`mr-4 w-12 h-12 rounded-xl flex items-center justify-center transition-all duration-300 ${
                    query.trim() && !isSearching ? 'bg-blue-600 text-white hover:bg-blue-700 hover:scale-105 shadow-md' : 'bg-slate-100 text-slate-300 cursor-not-allowed'
                  }`}
                >
                  {isSearching ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-arrow-up"></i>}
                </button>
              </div>
            </div>
          </form>

          {/* Suggestions */}
          {!result && !isSearching && (
            <div className="mt-8 flex flex-wrap justify-center gap-3 animate-fade-in-up">
              {suggestions.map((s, i) => (
                <button 
                  key={i}
                  onClick={() => handleSearch(s)}
                  className="px-4 py-2 bg-white border border-slate-200 rounded-full text-xs font-bold text-slate-500 hover:border-blue-300 hover:text-blue-600 hover:bg-blue-50 transition shadow-sm"
                >
                  {s}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Results Section */}
        {result && (
          <div className="w-full max-w-5xl mt-12 animate-fade-in-up">
            <div className="grid grid-cols-1 md:grid-cols-12 gap-8">

              {/* Prior Art Column (Left) */}
              <div className="md:col-span-5 space-y-6">
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200 h-full">
                  <div className="flex items-center gap-3 mb-6">
                    <div className="w-8 h-8 bg-rose-100 text-rose-600 rounded-lg flex items-center justify-center">
                      <i className="fa-solid fa-magnifying-glass"></i>
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-slate-900 leading-none">Prior Art Found</h3>
                      <p className="text-[10px] text-slate-400 mt-1">Sources from Google Search</p>
                    </div>
                  </div>

                  {result.existingPatents.length > 0 ? (
                     <div className="space-y-3">
                       {result.existingPatents.map((p, i) => (
                         <a key={i} href={p.uri} target="_blank" rel="noopener noreferrer" className="block p-4 rounded-2xl bg-slate-50 hover:bg-blue-50 border border-slate-100 hover:border-blue-200 transition group relative overflow-hidden">
                           <div className="flex justify-between items-start gap-3">
                             <div>
                               <h4 className="font-bold text-slate-800 text-sm group-hover:text-blue-700 line-clamp-2 leading-snug">{p.title}</h4>
                               <p className="text-[10px] text-slate-400 mt-1 truncate max-w-[200px]">{p.uri}</p>
                             </div>
                             <i className="fa-solid fa-external-link-alt text-xs text-slate-300 group-hover:text-blue-400 mt-1"></i>
                           </div>
                         </a>
                       ))}
                     </div>
                  ) : (
                    <div className="text-center py-10">
                       <i className="fa-solid fa-check-circle text-emerald-500 text-3xl mb-3"></i>
                       <p className="text-slate-600 font-bold">No exact matches found.</p>
                       <p className="text-slate-400 text-xs mt-1">Your idea appears to be unique based on our quick search.</p>
                    </div>
                  )}
                </div>
              </div>

              {/* Advice Column (Right) */}
              <div className="md:col-span-7 space-y-6">
                <div className="bg-slate-900 text-white p-8 rounded-3xl shadow-xl relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-32 bg-blue-600 rounded-full blur-[80px] opacity-20 group-hover:opacity-30 transition duration-1000"></div>

                  <div className="flex justify-between items-start mb-8 relative z-10">
                    <div>
                      <h3 className="text-xl font-bold">AI Assessment</h3>
                      <p className="text-slate-400 text-xs mt-1">Preliminary patentability check</p>
                    </div>
                    <span className={`px-4 py-1.5 rounded-xl text-xs font-black uppercase tracking-wide shadow-lg ${
                      result.noveltyEstimate.toLowerCase().includes('high') ? 'bg-emerald-500 text-white shadow-emerald-500/20' : 
                      result.noveltyEstimate.toLowerCase().includes('medium') ? 'bg-amber-500 text-white shadow-amber-500/20' : 'bg-rose-500 text-white shadow-rose-500/20'
                    }`}>
                      {result.noveltyEstimate} Novelty
                    </span>
                  </div>

                  <div className="space-y-5 relative z-10">
                    {result.advice.map((tip, i) => (
                      <div key={i} className="flex gap-4 items-start">
                        <div className="w-6 h-6 rounded-full bg-slate-800 flex items-center justify-center shrink-0 mt-0.5 border border-slate-700 text-blue-400 text-xs">
                           <i className="fa-solid fa-lightbulb"></i>
                        </div>
                        <p className="text-sm font-medium text-slate-300 leading-relaxed">{tip}</p>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-8 rounded-3xl shadow-xl text-white flex flex-col items-center text-center relative overflow-hidden">
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                  <h3 className="font-bold text-2xl mb-2 relative z-10">Ready to patent this?</h3>
